how many cotton fabric in the textiledat:
SELECT COUNT(*) AS Cotton_Fabric_Count
FROM textiledataset
WHERE TextileType = 'Cotton Fabric';

what is the total sales amount for cotto:
SELECT SUM(TotalAmount) AS TotalSalesAmountForCottonFabric 
FROM textiledataset 
WHERE TextileType = 'Cotton Fabric';

show first 10 rows of dataset textiledat:
SELECT TransactionID, CustomerName, TextileType, Category, Region, SalespersonName, OrderDate, Quantity, PricePerUnit, TotalAmount, PaymentMethod
FROM textiledataset
LIMIT 10;
